function toBase64(bytes:ByteArray):String {
    const base64Chars:String = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    var result:String = "";
    var i:int = 0;
    var len:int = bytes.length;
    while (i < len) {
        var a:int = bytes[i++] & 0xFF;
        var b:int = (i < len) ? bytes[i++] & 0xFF : -1;
        var c:int = (i < len) ? bytes[i++] & 0xFF : -1;
        var enc1:int = a >> 2;
        var enc2:int = ((a & 0x03) << 4) | (b >> 4);
        var enc3:int = ((b & 0x0F) << 2) | (c >> 6);
        var enc4:int = c & 0x3F;
        result += base64Chars.charAt(enc1) + base64Chars.charAt(enc2) +
                  ((b == -1) ? "==" : ((c == -1) ? "=" : base64Chars.charAt(enc3))) +
                  ((b == -1 || c == -1) ? "" : base64Chars.charAt(enc4));
    }
    return result;
}

// FUNGSI UTAMA - REVISI TOTAL (Tanpa Dispose)
function stageWebViewGif(base64String:String):void {
    // Hubungkan kembali ke stage jika sempat diputus
    webView.stage = null;

    // Atur ukuran viewport secara dinamis
    var rect:Rectangle;
    if (stage.nativeWindow.displayState == NativeWindowDisplayState.MAXIMIZED) {
        rect = new Rectangle(760, 250, 400, 270);
    } else {
        rect = new Rectangle(120, 300, 480, 340);
    }
    webView.viewPort = rect;

    // Suntikkan HTML baru berisi GIF Anda
    var html:String = '<html><body style="margin:0; padding:0; overflow:hidden; background-color:transparent;"><img src="data:image/gif;base64,' + base64String + '" style="width:100%; height:100%; object-fit:contain;"></body></html>';
    setTimeout(function():void { webView.loadString(html); }, 100);
    webView.stage = this.stage;
}

// FUNGSI PEMBERSIH - Mengosongkan konten tanpa menghancurkan objek
function cleanUpStageWebView():void {
    if (webView != null) { // Paksa browser internal memuat halaman kosong bersih
        webView.stage = null;              // Sembunyikan dari layar
        webView.viewPort = null;           // Kosongkan areanya sementara
    }
}

stage.nativeWindow.addEventListener(NativeWindowDisplayStateEvent.DISPLAY_STATE_CHANGE, onStateChange);
function onStateChange(e:NativeWindowDisplayStateEvent):void {
    if (webView && webView.stage != null) { 
        if (e.afterDisplayState == NativeWindowDisplayState.MAXIMIZED) {
            webView.viewPort = new Rectangle(760, 250, 400, 270);
        } else {
            webView.viewPort = new Rectangle(120, 300, 480, 340);
        }
    }
}

// --- Batas Kode Audio (Tetap sama) ---
function togglePlayPause(e:MouseEvent):void {
    if (isSoundPlaying) {
        if (soundChannel != null) {
            pausePosition = soundChannel.position;
            soundChannel.stop();
            soundChannel = null;
        }
        playBtn.gotoAndStop(1);
        isSoundPlaying = false;
    } else {
        if (pausePosition >= soundLength) {
            pausePosition = 0;
        }
        soundChannel = backsound.play(pausePosition);
        playBtn.gotoAndStop(2);
        isSoundPlaying = true;
        soundChannel.addEventListener(Event.SOUND_COMPLETE, onSoundComplete);
    }
}

function onSoundComplete(e:Event):void {
    soundChannel.removeEventListener(Event.SOUND_COMPLETE, onSoundComplete);
    soundChannel = null;
    isSoundPlaying = false;
    pausePosition = 0;
    progressBar.scaleX = 0;
    currentTime_txt.text = formatTime(0);
}

function updateProgress(e:Event):void {
    if (isSoundPlaying && soundChannel != null) {
        var pos:Number = soundChannel.position;
        if (soundLength > 0) {
            var percent:Number = pos / soundLength;
            var maxPercent:Number = Math.min(0.86, percent);
            percent = Math.min(1, Math.max(0, maxPercent));
            progressBar.scaleX = percent;
        }
        currentTime_txt.text = formatTime(pos);
    }
}

function formatTime(ms:Number):String {
    var seconds:Number = Math.floor(ms / 1000);
    var minutes:Number = Math.floor(seconds / 60);
    seconds = seconds % 60;
    var secStr:String = (seconds < 10) ? "0" + seconds : String(seconds);
    return minutes + ":" + secStr;
}

function cleanUpSound():void {
    if (soundChannel) {
        soundChannel.stop();
        soundChannel.removeEventListener(Event.SOUND_COMPLETE, onSoundComplete);
    }
    removeEventListener(Event.ENTER_FRAME, updateProgress);
    if (playBtn) {
        playBtn.gotoAndStop(1);
        playBtn.removeEventListener(MouseEvent.CLICK, togglePlayPause);
    }
}

