import flash.events.MouseEvent;
import flash.display.MovieClip;
import flash.utils.Timer;
import flash.events.TimerEvent;

if (MovieClip(root).skorTotalGame == undefined) {
    MovieClip(root).skorTotalGame = 0;
}

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

// --- TIMER DISPLAY DTB ---
var timerDisplayDTB:Timer = new Timer(1000);
var isDisplayTimerJalan:Boolean = false;

function updateTimerDTB():void {
    var menit:int = Math.floor(MovieClip(root).waktuTotalGame / 60);
    var detik:int = MovieClip(root).waktuTotalGame % 60;
    var teksMenit:String = (menit < 10) ? "0" + menit : String(menit);
    var teksDetik:String = (detik < 10) ? "0" + detik : String(detik);
    txt_timer.text = teksMenit + "." + teksDetik;
    stage.invalidate(); // PERUBAHAN: Memaksa render agar tidak ketahan
}

function onTickDisplayDTB(e:TimerEvent):void {
    MovieClip(root).waktuTotalGame++; // Memastikan detik selalu maju
    updateTimerDTB();
}

function mulaiDisplayTimerDTB():void {
    if (!isDisplayTimerJalan) {
        timerDisplayDTB.addEventListener(TimerEvent.TIMER, onTickDisplayDTB);
        timerDisplayDTB.start();
        isDisplayTimerJalan = true;
    }
    updateTimerDTB();
}

// 1. DATABASE 5 LEVEL DTB
var dataLevelDTB:Array = [
    null,
    { soal: "#include &lt;iostream&gt;\nusing namespace std;\n\nint main() {\n  // Tampilkan teks ke layar\n  [ Zona 1 ] &lt;&lt; \"Halo, C++!\";\n  return 0;\n}", kunci: "btn_jawaban2", nilaiBlok: ["cin", "cout", "get", "print"] },
    { soal: "int umur = 20;\n\n// Cek syarat minimal umur\n[ Zona 1 ] (umur >= 18) {\n  cout &lt;&lt; \"Boleh masuk\";\n}", kunci: "btn_jawaban1", nilaiBlok: ["if", "else", "for", "switch"] },
    { soal: "char grade = 'A';\nswitch (grade) {\n  case 'A': \n    cout &lt;&lt; \"Sangat baik\"; \n    [ Zona 1 ]\n  case 'B': \n    cout &lt;&lt; \"Baik\";\n}", kunci: "btn_jawaban4", nilaiBlok: ["stop;", "exit;", "return;", "break;"] },
    { soal: "// Menampilkan angka 0 sampai 4\n[ Zona 1 ] (int i = 0; i &lt; 5; i++) {\n  cout &lt;&lt; i &lt;&lt; \" \";\n}", kunci: "btn_jawaban3", nilaiBlok: ["while", "do", "for", "loop"] },
    { soal: "int x = 10;\ndo {\n  cout &lt;&lt; \"Nilai x: \" &lt;&lt; x;\n  x++;\n} [ Zona 1 ] (x &lt; 5);", kunci: "btn_jawaban2", nilaiBlok: ["if", "while", "until", "for"] }
];

var soalAsli:String;
var jawabanBenarDTB:String;
var jawabanPemain:MovieClip;
var levelDTB:int = 1;

var posisiAwalX:Array = [];
var posisiAwalY:Array = [];
var posisiTersimpan:Boolean = false;

// 2. FUNGSI SETUP LEVEL
function setupLevelDTB():void {
    jawabanPemain = null;

    txt_poinangka.background = false;
    txt_poinangka.border = false;
    txt_poinangka.text = String(MovieClip(root).skorTotalGame);

    var dataSekarang:Object = dataLevelDTB[levelDTB];
    soalAsli = dataSekarang.soal;
    jawabanBenarDTB = dataSekarang.kunci;
    txt_soal.htmlText = soalAsli;

    for (var j:int = 1; j <= 4; j++) {
        var btn:MovieClip = this["btn_jawaban" + j] as MovieClip;
        if (btn != null) {
            btn.buttonMode = true;

            if (!posisiTersimpan) {
                posisiAwalX[j] = btn.x;
                posisiAwalY[j] = btn.y;
            }

            btn.x = posisiAwalX[j];
            btn.y = posisiAwalY[j];
            btn.startX = posisiAwalX[j];
            btn.startY = posisiAwalY[j];

            btn.nilaiTeks = dataSekarang.nilaiBlok[j - 1];

            if (btn["txt_label"] != undefined) {
                btn["txt_label"].text = dataSekarang.nilaiBlok[j - 1];
            }

            btn.removeEventListener(MouseEvent.MOUSE_DOWN, ambilBlok);
            btn.removeEventListener(MouseEvent.MOUSE_UP, lepasBlok);
            btn.addEventListener(MouseEvent.MOUSE_DOWN, ambilBlok);
            btn.addEventListener(MouseEvent.MOUSE_UP, lepasBlok);
        }
    }

    posisiTersimpan = true;

    btn_lanjutdtb.removeEventListener(MouseEvent.CLICK, cekSkorDTB);
    btn_lanjutdtb.addEventListener(MouseEvent.CLICK, cekSkorDTB);

    mulaiDisplayTimerDTB();
}

// 3. MEKANIK DRAG
function ambilBlok(e:MouseEvent):void {
    var blok:MovieClip = e.currentTarget as MovieClip;
    setChildIndex(blok, numChildren - 1);
    blok.startDrag();
}

// 4. MEKANIK DROP
function lepasBlok(e:MouseEvent):void {
    var blok:MovieClip = e.currentTarget as MovieClip;
    blok.stopDrag();

    if (blok.hitTestObject(dropZone)) {
		dropZone.gotoAndStop(2);
        blok.x = dropZone.x + (dropZone.width / 2) - (blok.width / 2);
        blok.y = dropZone.y + (dropZone.height / 2) - (blok.height / 2);

        jawabanPemain = blok;

        var teksMerah:String = "<font color='#FF0000'>" + blok.nilaiTeks + "</font>";
        txt_soal.htmlText = soalAsli.replace("[ Zona 1 ]", teksMerah);

        for (var k:int = 1; k <= 4; k++) {
            var btnLain:MovieClip = this["btn_jawaban" + k] as MovieClip;
            if (btnLain != blok) {
                btnLain.x = btnLain.startX;
                btnLain.y = btnLain.startY;
            }
        }
    } else {
		dropZone.gotoAndStop(1);
        blok.x = blok.startX;
        blok.y = blok.startY;
        if (jawabanPemain == blok) {
            jawabanPemain = null;
            txt_soal.htmlText = soalAsli;
        }
    }
}

// 5. VALIDASI SKOR & PINDAH FRAME
function cekSkorDTB(e:MouseEvent):void {

    if (jawabanPemain != null) {
        if (jawabanPemain.name == jawabanBenarDTB) {
            MovieClip(root).skorTotalGame += 25;

			var formatTeks:TextFormat = txt_poinangka.getTextFormat(); 
        txt_poinangka.text = String(MovieClip(root).skorTotalGame);
        txt_poinangka.setTextFormat(formatTeks); // Paksa text format diaplikasikan ulang

        stage.invalidate();
        }
    }

    // PERUBAHAN: Pause timer sebelum pindah frame di DTB
    if (levelDTB < 5) {
        levelDTB++;
        timerDisplayDTB.stop(); 
        nextFrame();
        isDisplayTimerJalan = false; 
    } else {
        MovieClip(this["btn_jawaban1"]).visible = false;
        MovieClip(this["btn_jawaban2"]).visible = false;
        MovieClip(this["btn_jawaban3"]).visible = false;
        MovieClip(this["btn_jawaban4"]).visible = false;

        timerDisplayDTB.stop();
        timerDisplayDTB.removeEventListener(TimerEvent.TIMER, onTickDisplayDTB);
        isDisplayTimerJalan = false;
        gotoAndStop(1, "Halaman Game Skor");
    }
}

