import flash.events.MouseEvent;
import flash.display.Shape;
import flash.display.MovieClip;
import flash.utils.Timer;
import flash.events.TimerEvent;

// --- SETUP VARIABEL GLOBAL SKOR & WAKTU ---
if (MovieClip(root).skorTotalGame == undefined) {
    MovieClip(root).skorTotalGame = 0;
}
if (MovieClip(root).waktuTotalGame == undefined) {
    MovieClip(root).waktuTotalGame = 0;
}

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

var levelCTD:int = 1;
var gameSelesai:Boolean = false;
var startX:Number;
var startY:Number;
var activeBlock:MovieClip;
var activeIndex:int;

// --- VARIABEL TIMER STOPWATCH ---
var timerGame:Timer = new Timer(1000);
var isTimerBerjalan:Boolean = false;

// 1. Membuat Wadah Garis
var lines:Array = [];
var indexGaris:int;

for (indexGaris = 1; indexGaris <= 4; indexGaris++) {
    var line:Shape = new Shape();
    addChild(line);
    lines[indexGaris] = line;
}

// 2. KAMUS JAWABAN UNTUK 5 LEVEL
var semuaKunci:Array = [
    null,
    { "btnkiri1":"btnkanan4", "btnkiri2":"btnkanan3", "btnkiri3":"btnkanan1", "btnkiri4":"btnkanan2" },
    { "btnkiri1":"btnkanan4", "btnkiri2":"btnkanan1", "btnkiri3":"btnkanan3", "btnkiri4":"btnkanan2" },
    { "btnkiri1":"btnkanan1", "btnkiri2":"btnkanan2", "btnkiri3":"btnkanan3", "btnkiri4":"btnkanan4" },
    { "btnkiri1":"btnkanan4", "btnkiri2":"btnkanan3", "btnkiri3":"btnkanan2", "btnkiri4":"btnkanan1" },
    { "btnkiri1":"btnkanan2", "btnkiri2":"btnkanan4", "btnkiri3":"btnkanan1", "btnkiri4":"btnkanan3" }
];

// --- FUNGSI TIMER MAJU ---
function jalankanTimer():void {
    if (!isTimerBerjalan) {
        timerGame.addEventListener(TimerEvent.TIMER, hitungMaju);
        timerGame.start();
        isTimerBerjalan = true;
    }
    updateTeksTimer();
}

function hitungMaju(e:TimerEvent):void {
    MovieClip(root).waktuTotalGame++;
    updateTeksTimer();
}

function updateTeksTimer():void {
    var menit:int = Math.floor(MovieClip(root).waktuTotalGame / 60);
    var detik:int = MovieClip(root).waktuTotalGame % 60;
    var teksMenit:String = (menit < 10) ? "0" + menit : String(menit);
    var teksDetik:String = (detik < 10) ? "0" + detik : String(detik);
    var teksWaktu:String = teksMenit + "." + teksDetik;

    if (MovieClip(root)["txt_timer"] != null) {
        MovieClip(root)["txt_timer"].text = teksWaktu;
        stage.invalidate(); // PERUBAHAN: Memaksa render agar tidak lag
    }
}

// 3. FUNGSI SETUP LEVEL
function setupLevel():void {
    gameSelesai = false;

    if (MovieClip(root)["txt_poinangka"] != null) {
        MovieClip(root)["txt_poinangka"].text = String(MovieClip(root).skorTotalGame);
    }

    for (var j:int = 1; j <= 4; j++) {
        lines[j].graphics.clear();

        var btn:MovieClip = this["btnkiri" + j] as MovieClip;
        if (btn != null) {
            btn.buttonMode = true;
            btn.index = j;
            btn.connectedTo = null;

            btn.removeEventListener(MouseEvent.MOUSE_DOWN, onDragStart);
            btn.addEventListener(MouseEvent.MOUSE_DOWN, onDragStart);
        }
    }

    btn_lanjutctd.removeEventListener(MouseEvent.CLICK, onLanjutClick);
    btn_lanjutctd.addEventListener(MouseEvent.CLICK, onLanjutClick);

    jalankanTimer();
}

// 4. LOGIKA DRAG & DROP
function onDragStart(e:MouseEvent):void {
    if (gameSelesai) return;
    activeBlock = e.currentTarget as MovieClip;
    activeIndex = activeBlock.index;
    startX = activeBlock.x + activeBlock.width;
    startY = activeBlock.y + (activeBlock.height / 2);

    stage.addEventListener(MouseEvent.MOUSE_MOVE, onDragging);
    stage.addEventListener(MouseEvent.MOUSE_UP, onDragDrop);
}

function onDragging(e:MouseEvent):void {
    var currentLine:Shape = lines[activeIndex];
    currentLine.graphics.clear();
    currentLine.graphics.lineStyle(5, 0x3399FF);
    currentLine.graphics.moveTo(startX, startY);
    currentLine.graphics.lineTo(mouseX, mouseY);
}

function onDragDrop(e:MouseEvent):void {
    stage.removeEventListener(MouseEvent.MOUSE_MOVE, onDragging);
    stage.removeEventListener(MouseEvent.MOUSE_UP, onDragDrop);

    var currentLine:Shape = lines[activeIndex];
    var isConnected:Boolean = false;

    for (var k:int = 1; k <= 4; k++) {
        var targetBtn:MovieClip = this["btnkanan" + k] as MovieClip;
        if (targetBtn.hitTestPoint(mouseX, mouseY, true)) {
            var targetX:Number = targetBtn.x;
            var targetY:Number = targetBtn.y + (targetBtn.height / 2);

            currentLine.graphics.clear();
            currentLine.graphics.lineStyle(5, 0x297ACC);
            currentLine.graphics.moveTo(startX, startY);
            currentLine.graphics.lineTo(targetX, targetY);

            activeBlock.connectedTo = targetBtn.name;
            isConnected = true;
            break;
        }
    }
    if (!isConnected) {
        currentLine.graphics.clear();
        activeBlock.connectedTo = null;
    }
}

// 5. PENILAIAN & PINDAH SCENE
function onLanjutClick(e:MouseEvent):void {
    if (gameSelesai) return;

    var skorLevelIni:int = 0;
    var kunciSekarang:Object = semuaKunci[levelCTD];

    for (var m:int = 1; m <= 4; m++) {
        var kiri:MovieClip = this["btnkiri" + m] as MovieClip;
        if (kiri.connectedTo != null) {
            if (kiri.connectedTo == kunciSekarang[kiri.name]) {
                skorLevelIni += 25;
            }
        }
    }

    MovieClip(root).skorTotalGame += skorLevelIni;
    if (MovieClip(root)["txt_poinangka"] != null) {
        MovieClip(root)["txt_poinangka"].text = String(MovieClip(root).skorTotalGame);
    }

    // PERUBAHAN: Pause timer sebelum pindah frame
    if (levelCTD < 5) {
        levelCTD++;
        timerGame.stop(); 
        nextFrame();
        isTimerBerjalan = false; 
    } else {
        timerGame.stop();
        timerGame.removeEventListener(TimerEvent.TIMER, hitungMaju);
        isTimerBerjalan = false;
        gotoAndStop(1, "Halaman Game - DTB");
    }
}

setupLevel();

